var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"스승님, 현재 적과의 거리는 100 되겠습니다.","JPN":"師匠、現在敵との距離は100になります。","ENG":"Master, the distance between us and the enemy is pointing at 100.","TWN":"師父，現在和敵人之間的距離大概是100。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"눈대중으로 봐도 만 단위는 훌쩍 넘는데요. 괜찮으시겠어요?","JPN":"ざっと見積もっても、万は超える敵の数です。大丈夫ですか？","ENG":"It looks like it's a lot more than ten thousands, from plain eyesight alone. Are you sure about this?","TWN":"目測數量在一萬單位以上。沒關係嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"상관없다. 네헤모트가 혼란에서 벗어나기 전에 끝을 내야 하니까.","JPN":"構わん。ネヘモトが混乱に陥っている間にとどめを刺さねばならんからな。","ENG":"It doesn't matter. We must put an end to this before Nehemoth clears his head.","TWN":"不要緊。我們必須在貝赫莫特回過神之前結束。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"검이 가리키는 방향은 어떻지, 신입?","JPN":"剣はどの方向を示している、新人？","ENG":"Where is the sword pointing at, rookie?","TWN":"劍指著的方向是哪邊，新人？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이쪽이 맞아. 계속 끌어당기는 느낌이야.","JPN":"こっちの方向で合っているよ。ずっと引っ張られている感じ。","ENG":"We're on the right track. It feels like it's pulling us towards it.","TWN":"是這邊沒錯。它好像一直想要拉我們去那個方向。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"좋다. 그렇다면 지체할 것 없군.","JPN":"よし。ならばさっそく行動に移す。","ENG":"Affirmative. Well then, there will be no need to slow down.","TWN":"很好。那就不用耽誤時間了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"전원, 이대로 적진을 일점 돌파해서 네헤모트를 추격한다.","JPN":"全員、このまま敵陣を一点突破し、ネヘモトを追撃する。","ENG":"All members, break through the enemies and track down Nehemoth.","TWN":"全體維持隊型，集中突破敵人，繼續追擊貝赫莫特！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"알겠어, 소대장!","JPN":"わかった、小隊長！","ENG":"Got it, Commander!","TWN":"是，小隊長！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"뭘 <color=#ffd34c>알겠어!</color> 야?","JPN":"何が<color=#ffd34c>わかった！</color>よ？","ENG":"What do you mean, \\"<color=#ffd34c>got it</color>\\"?!","TWN":"<color=#ffd34c>是什麼是</color>？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"펜릴 소대장님, 그냥 싸우는 것도 아니고 저 많은 숫자를 우리만으로 뚫고 가자고요?","JPN":"フェンリル小隊長、ただ戦闘をするだけならわかりますが、あの数を私たちだけで突破するんですか？","ENG":"Fenrir Commander, do you really think it's possible to break through all of them with just us?","TWN":"芬里爾小隊長，這又不是單純地打架，光靠我們要突破那麼多敵人嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"애초에 본래 목표는 현실세계로 이어지는 통로를 파괴하는 것 아니었나요?","JPN":"そもそもの目標は現実世界に繋がる通路を破壊することではありませんでしたか？","ENG":"Wasn't our objective destroying the tunnel linked to the Normalside?","TWN":"我們一開始的目標不是破壞連接現實世界的通道嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그렇지. 그런 중요한 곳을 지금 누가 지키고 있을 것 같나?","JPN":"そうだな。その重要なポイントを今誰が守っていると思う？","ENG":"Precisely. And who do you think will be guarding such an important spot?","TWN":"沒錯。所以你想想，那麼重要的地方，現在誰會在那裡把守呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"……네헤모트겠죠.","JPN":"……ネヘモト。","ENG":"...Nehemoth.","TWN":"……貝赫莫特。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그래. 녀석이 자결할 방법이라도 발견하지 않는 한 이제 충돌은 불가피하다.","JPN":"そうだ。奴が自決する方法でも見つけない限り、どの道もう衝突は避けられない。","ENG":"Correct. Unless you find a way for him to kill himself, conflict is inevitable.","TWN":"對。只要那傢伙沒想過自我了結，衝突就不可避免。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"이 회사는 어째 하는 일마다 항상 이렇게 꼬인다니까. 못 살겠어, 진짜.","JPN":"この会社はやることなすことが全部面倒くさい方向に行っちゃうんだから、まったくもう。","ENG":"Oh boy... Things always get messed up working for this company.","TWN":"……真是受不了。這家公司怎麼衰事那麼多。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"거리 15. 손목 다치지 않게 다들 미리 풀어 두세요.","JPN":"距離は15。手首を怪我しないようにみんなよくほぐしておいてくださいね。","ENG":"Distance pointing at 15. Warm yourselves up so that you don't get hurt.","TWN":"距離15。大家把握最後時間拉拉筋，否則手腕會拉傷的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전군, 여기가 우리의 마지막 전장이다!","JPN":"全軍、ここが我々の最後の戦場だ！","ENG":"All troops, this will be our final battle!","TWN":"所有人聽著，這裡是我們最後的戰場！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L36_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원이, 그대들의 가족들이 되살아날 성역에서 기다리고 있다!","JPN":"救いが、そなたたちの家族が、甦るべき聖域で待っている！","ENG":"Salvation awaits, in the sanctuary where your families will be resurrected!","TWN":"救贖正在等著我們，你們的家人將在聖域裡獲得新生！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"거리 5입니다, 스승님!","JPN":"距離は5です、師匠！","ENG":"Distance reaching 5, Master!","TWN":"距離5，最後一段了，師父！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"전방은 내가 맡는다! 날 믿고 따라오도록!","JPN":"前方は私がやる！　信じてついて来い！","ENG":"I'll take care of the front! Follow me!","TWN":"前方交給我！相信我，跟緊了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};